import{_ as e,o,c as a,a2 as n}from"./chunks/framework.C2B0glpm.js";const p=JSON.parse('{"title":"Context Window","description":"","frontmatter":{},"headers":[],"relativePath":"en/usage/context-window.md","filePath":"en/usage/context-window.md"}'),s={name:"en/usage/context-window.md"};function i(r,t,l,c,d,u){return o(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="context-window" tabindex="-1">Context Window <a class="header-anchor" href="#context-window" aria-label="Permalink to &quot;Context Window&quot;">​</a></h1><p>Manage the context window and conversation length.</p><p>TurboDev tracks token usage in real-time and displays it in the status bar. When the context window fills up, auto-compaction keeps the conversation going.</p><h2 id="token-usage" tabindex="-1">Token Usage <a class="header-anchor" href="#token-usage" aria-label="Permalink to &quot;Token Usage&quot;">​</a></h2><p>The status bar shows a token indicator like <code>1.24K/128K</code>:</p><ul><li><strong>Left value</strong> — Estimated tokens used (including system prompt, conversation history, and tool results)</li><li><strong>Right value</strong> — Maximum context length for the current model</li></ul><h3 id="color-coding" tabindex="-1">Color Coding <a class="header-anchor" href="#color-coding" aria-label="Permalink to &quot;Color Coding&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Color</th><th>Usage</th><th>Behavior</th></tr></thead><tbody><tr><td>Green</td><td>Below 50%</td><td>Normal operation</td></tr><tr><td>Yellow</td><td>50%–75%</td><td>Warning — consider compacting</td></tr><tr><td>Red</td><td>Above 75%</td><td>Auto-compaction triggers at 85%</td></tr></tbody></table><h2 id="auto-compaction" tabindex="-1">Auto-Compaction <a class="header-anchor" href="#auto-compaction" aria-label="Permalink to &quot;Auto-Compaction&quot;">​</a></h2><p>When token usage reaches <strong>75%</strong>, TurboDev notifies you. At <strong>85%</strong>, the conversation is automatically compacted:</p><ol><li>The full conversation is sent to the LLM</li><li>The LLM generates a concise summary</li><li>The conversation is replaced with the summary</li><li>You can continue chatting normally</li></ol><p>The summary preserves key decisions, code changes, and context needed for the ongoing task.</p><h2 id="manual-compaction" tabindex="-1">Manual Compaction <a class="header-anchor" href="#manual-compaction" aria-label="Permalink to &quot;Manual Compaction&quot;">​</a></h2><p>Use <code>/compact</code> at any time to manually trigger compaction:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/compact</span></span></code></pre></div><p>This is useful when:</p><ul><li>You want to free up context before a complex task</li><li>The conversation has drifted and you want a clean slate</li><li>You&#39;re approaching the context limit and want to compact on your terms</li></ul><h2 id="how-tokens-are-counted" tabindex="-1">How Tokens Are Counted <a class="header-anchor" href="#how-tokens-are-counted" aria-label="Permalink to &quot;How Tokens Are Counted&quot;">​</a></h2><p>TurboDev estimates tokens at approximately <strong>4 characters per token</strong>. This is a close approximation for most LLM models. The count includes:</p><ul><li><strong>System prompt</strong> — Agent instructions, tool definitions, AGENTS.md content</li><li><strong>Conversation history</strong> — All user and assistant messages</li><li><strong>Tool results</strong> — Output from file reads, bash commands, etc.</li></ul><p>The token count is displayed immediately on startup (system prompt only) and updated after every message exchange.</p><h2 id="cost-tracking" tabindex="-1">Cost Tracking <a class="header-anchor" href="#cost-tracking" aria-label="Permalink to &quot;Cost Tracking&quot;">​</a></h2><p>TurboDev fetches per-token pricing from OpenRouter and calculates the real-time cost:</p><ul><li><strong>Input tokens</strong> — Tokens sent to the model (system prompt + history + new message)</li><li><strong>Output tokens</strong> — Tokens generated by the model (response)</li><li><strong>Cost formula</strong> — <code>(inputTokens × promptPrice) + (outputTokens × completionPrice)</code></li></ul><p>The cumulative cost is shown in the status bar (e.g., <code>$0.0023</code>) and persisted with the session.</p><h2 id="back-to-usage" tabindex="-1">Back to Usage <a class="header-anchor" href="#back-to-usage" aria-label="Permalink to &quot;Back to Usage&quot;">​</a></h2><ul><li><a href="/TurboDev/en/usage/">Terminal UI</a></li><li><a href="/TurboDev/en/usage/commands.html">Commands</a></li></ul>',27)])])}const m=e(s,[["render",i]]);export{p as __pageData,m as default};
